import base64
from PySide6.QtGui import QPixmap
import re
import unicodedata

_UMLAUTS = str.maketrans({
    "ä": "ae", "ö": "oe", "ü": "ue", "ß": "ss",
    "Ä": "ae", "Ö": "oe", "Ü": "ue",
})

def slugify(s: str) -> str:
    s = str(s).strip().translate(_UMLAUTS).lower()
    s = unicodedata.normalize("NFKD", s).encode("ascii", "ignore").decode("ascii")
    s = re.sub(r"[^a-z0-9]+", "_", s)
    return s.strip("_")

